
const MANUAL_MODULES = [{"id": "modulo-01", "number": 1, "title": "Via aérea e intubação orotraqueal", "file": "modules/modulo_01_via_aerea_iot.html", "sourceFile": "src/data/modules/modulo_01_via_aerea_iot.html", "htmlBase64": "", "sizeKB": 476.9, "imageCount": 4, "externalImages": 0, "relativeImages": 0, "scriptCount": 0, "styleCount": 1, "detailsCount": 43}, {"id": "modulo-02", "number": 2, "title": "Pós-intubação e confirmação", "file": "modules/modulo_02_pos_intubacao_confirmacao.html", "sourceFile": "src/data/modules/modulo_02_pos_intubacao_confirmacao.html", "htmlBase64": "", "sizeKB": 64.0, "imageCount": 0, "externalImages": 0, "relativeImages": 0, "scriptCount": 0, "styleCount": 1, "detailsCount": 24}, {"id": "modulo-03", "number": 3, "title": "Ventilação mecânica invasiva", "file": "modules/modulo_03_ventilacao_mecanica.html", "sourceFile": "src/data/modules/modulo_03_ventilacao_mecanica.html", "htmlBase64": "", "sizeKB": 58.2, "imageCount": 0, "externalImages": 0, "relativeImages": 0, "scriptCount": 1, "styleCount": 1, "detailsCount": 15}, {"id": "modulo-04", "number": 4, "title": "Manutenção de sedoanalgesia em UTI", "file": "modules/modulo_04_manutencao_sedoanalgesia.html", "sourceFile": "src/data/modules/modulo_04_manutencao_sedoanalgesia.html", "htmlBase64": "", "sizeKB": 57.1, "imageCount": 0, "externalImages": 0, "relativeImages": 0, "scriptCount": 1, "styleCount": 1, "detailsCount": 9}, {"id": "modulo-05", "number": 5, "title": "Drogas vasoativas em medicina intensiva", "file": "modules/modulo_05_drogas_vasoativas.html", "sourceFile": "src/data/modules/modulo_05_drogas_vasoativas.html", "htmlBase64": "", "sizeKB": 65.3, "imageCount": 0, "externalImages": 0, "relativeImages": 0, "scriptCount": 1, "styleCount": 1, "detailsCount": 26}, {"id": "modulo-06", "number": 6, "title": "Calculadoras interativas", "file": "modules/modulo_06_calculadoras_interativas.html", "sourceFile": "src/data/modules/modulo_06_calculadoras_interativas.html", "htmlBase64": "", "sizeKB": 139.3, "imageCount": 0, "externalImages": 0, "relativeImages": 0, "scriptCount": 1, "styleCount": 1, "detailsCount": 7}];
const ManualLibrary = (() => {
let currentIndex=0;
function decodeB64Utf8(b64){const bin=atob(b64);const bytes=Uint8Array.from(bin,c=>c.charCodeAt(0));return new TextDecoder('utf-8').decode(bytes);}
function stripHtml(html){const doc=new DOMParser().parseFromString(html,'text/html');return (doc.body?.innerText||'').replace(/\s+/g,' ').trim();}
function buildModuleList(){const list=document.getElementById('moduleList');list.innerHTML='';MANUAL_MODULES.forEach((m,i)=>{const btn=document.createElement('button');btn.className='module-btn'+(i===currentIndex?' active':'');btn.type='button';btn.innerHTML=`<strong>Módulo ${m.number}</strong><span>${m.title}</span>`;btn.addEventListener('click',()=>loadModule(i));list.appendChild(btn);});}
function loadModule(index){currentIndex=index;buildModuleList();const m=MANUAL_MODULES[index];document.getElementById('currentTitle').textContent=`Módulo ${m.number} — ${m.title}`;document.getElementById('moduleFrame').srcdoc=decodeB64Utf8(m.htmlBase64);setTimeout(()=>window.scrollTo({top:0,behavior:'smooth'}),50);}
function reloadModule(){loadModule(currentIndex);}
function frameTop(){try{document.getElementById('moduleFrame').contentWindow.scrollTo({top:0,behavior:'smooth'});}catch(e){loadModule(currentIndex);}}
function openModuleRaw(){window.open(MANUAL_MODULES[currentIndex].file,'_blank');}
function search(query){const q=(query||'').trim().toLowerCase();const box=document.getElementById('searchResults');if(!q||q.length<3){box.classList.remove('show');box.innerHTML='';return;}const results=[];MANUAL_MODULES.forEach((m,idx)=>{const txt=stripHtml(decodeB64Utf8(m.htmlBase64)).toLowerCase();const pos=txt.indexOf(q);if(pos>=0){results.push({idx,title:`Módulo ${m.number} — ${m.title}`,excerpt:txt.slice(Math.max(0,pos-90),Math.min(txt.length,pos+180))});}});if(!results.length){box.innerHTML='<strong>Nenhum resultado encontrado.</strong>';box.classList.add('show');return;}box.innerHTML='<strong>Resultados da busca</strong>'+results.map(r=>`<button type="button" data-idx="${r.idx}"><b>${r.title}</b><br><span>${r.excerpt}...</span></button>`).join('');box.querySelectorAll('button[data-idx]').forEach(btn=>btn.addEventListener('click',()=>{loadModule(parseInt(btn.getAttribute('data-idx'),10));box.classList.remove('show');}));box.classList.add('show');}
function init(){buildModuleList();loadModule(0);document.getElementById('searchInput').addEventListener('input',e=>search(e.target.value));document.getElementById('reloadBtn').addEventListener('click',reloadModule);document.getElementById('topBtn').addEventListener('click',frameTop);document.getElementById('rawBtn').addEventListener('click',openModuleRaw);}
return {init,loadModule,reloadModule,frameTop,search,modules:MANUAL_MODULES};
})();
document.addEventListener('DOMContentLoaded', ManualLibrary.init);
